INSERT INTO bicycles (name, short_description, price, inventory, img_url, slug, seo_title, seo_description, long_description)
VALUES
('Roadrunner', 'A lightweight aluminum frame, ideal for a beginner wanting to go fast.', 1899.99, 10, '/images/roadrunner-road-bike.png', 'roadrunner-road-bike', 'Roadrunner | A lightweight beginner road bike', 'A lightweight, aluminum bike, perfect for easing into the sport of cycling.', 'The Roadrunner is the perfect beginner road bike for riders who want to experience the speed and efficiency of cycling without the complexity or cost of a high-end racing machine. Built around a lightweight aluminum frame, it delivers responsive handling and quick acceleration, making it easy to gain confidence whether you''re riding through town, exploring local roads, or building fitness on longer weekend rides. Its balanced geometry provides a comfortable position that helps new cyclists feel in control from the very first mile.
Designed for versatility and everyday performance, the Roadrunner offers the smooth, efficient ride that makes road cycling so rewarding. The lightweight construction helps riders maintain speed with less effort, while the stable handling inspires confidence on a variety of paved surfaces. Whether you''re training for your first charity ride, commuting to work, or simply looking for a reliable entry-level road bike, the Roadrunner combines comfort, speed, and value in a package that''s ready to grow with your cycling journey.'),
('Falcon', 'A lightweight carbon fiber frame, ideal for serious riders who seek speed and agility.', 2499.99, 10, '/images/falcon-road-bike.png', 'falcon-carbon-road-bike', 'Falcon | A fast carbon fiber road bike', 'Made of lightweight, durable carbon fiber, this is a sporty step up from your first bike.', 'Engineered for riders who demand exceptional performance, the Falcon combines a lightweight carbon fiber frame with razor-sharp handling to create a road bike built for speed. The advanced carbon construction reduces weight while maximizing stiffness, allowing more of your power to reach the pavement with every pedal stroke. Whether you''re attacking steep climbs, sprinting out of corners, or maintaining a fast pace on long stretches of open road, the Falcon delivers the responsiveness and efficiency that serious cyclists expect from a high-performance carbon road bike.
Beyond its impressive speed, the Falcon is designed to inspire confidence in every ride. Its agile geometry provides precise cornering and quick acceleration, making it equally at home in competitive events, spirited group rides, and demanding training sessions. The carbon frame also helps absorb road vibrations for a smoother ride, reducing fatigue during long days in the saddle. For cyclists seeking a premium performance road bike that blends lightweight construction, agility, and race-inspired capability, the Falcon is ready to help you reach your next personal best.'),
('Warthog', 'A durable steel frame ideal for anyone just getting into the exhilarating sport of gravel riding.', 1699.99, 10, '/images/warthog-gravel-bike.png', 'warthog-gravel-bike', 'Warthog | A beginner-friendly gravel bike', 'A perfect bike for those looking to try gravel riding.', 'Built to tackle rough roads, backcountry routes, and everything in between, the Warthog is a dependable gravel bike designed for riders eager to discover the freedom of riding beyond the pavement. Its durable steel frame delivers the strength and reliability needed for long adventures while providing the smooth, forgiving ride quality that steel is known for. From crushed gravel paths and forest service roads to mixed-surface weekend explorations, the Warthog offers a stable and confidence-inspiring platform for cyclists taking their first steps into the exciting world of gravel riding.
The Warthog''s versatile design makes it equally capable on daily rides and all-day adventures. The steel frame helps absorb bumps and vibrations from uneven terrain, reducing fatigue and keeping you comfortable when the road turns rough. Predictable handling and rugged construction allow riders to focus on the journey ahead, whether they''re exploring new routes, commuting on varied surfaces, or joining their first gravel event. For cyclists seeking an approachable and adventure-ready entry-level gravel bike, the Warthog combines durability, comfort, and capability in a package built to roam far beyond the beaten path.'),
('Jackal', 'A spritely titanium frame, great for more experienced riders to shred the logging roads.', 1899.99, 10, '/images/jackal-gravel-bike.png', 'jackal-titanium-gravel-bike', 'Jackal | A gravel bike for pushing the limits', 'If you''re ready to take gravel riding to the next level, this is the gravel bike for you.', 'The Jackal is a premium titanium gravel bike engineered for experienced riders who demand performance, durability, and all-day comfort on challenging terrain. Its lightweight titanium frame delivers an exceptional balance of strength, responsiveness, and ride quality, making it an ideal choice for fast-paced adventures on logging roads, fire roads, and remote gravel routes. Titanium''s natural resilience helps smooth out rough surfaces while maintaining the lively feel and efficient power transfer that performance-oriented cyclists appreciate.
Designed for riders who like to push the pace off the beaten path, the Jackal offers confident handling and precise control across a wide range of conditions. The frame''s responsive character encourages quick acceleration and agile maneuvering, while its rugged construction is built to withstand years of demanding rides. Whether you''re tackling long-distance gravel events, exploring backcountry routes, or chasing personal records on your favorite forest roads, the Jackal delivers the refined performance and versatility expected from a high-end adventure gravel bike.'),
('Rhino', 'A beginner-friendly mountain bike great for tackling mountain roads.', 1599.99, 10, '/images/rhino-mountain-bike.png', 'rhino-mountain-bike', 'Rhino | A strong choice for your first mountain bike', 'The Rhino has everything you need, and nothing you don''t, to get into the wild world of MTB.', 'The Rhino is a dependable beginner mountain bike built for riders who are ready to explore dirt roads, mountain trails, and rugged outdoor terrain with confidence. Designed with new cyclists in mind, it offers stable handling and a comfortable riding position that make it easy to stay in control on uneven surfaces. Whether you''re venturing onto your first trail, cruising along mountain roads, or enjoying weekend rides through local parks, the Rhino provides the versatility and confidence needed to enjoy every adventure.
Built to handle a variety of off-road conditions, the Rhino helps riders develop their skills while maintaining a smooth and predictable ride. Its trail-friendly design inspires confidence when climbing hills, navigating loose gravel, or rolling over rough terrain, making it an excellent choice for those new to mountain biking. From casual outdoor excursions to longer off-road journeys, the Rhino delivers the durability, comfort, and capability that riders look for in an entry-level mountain bike designed to grow alongside their experience.'),
('Beast', 'A serious, full-suspension mountain bike for those looking to fly down bumpy single-track courses.', 2399.99, 10, '/images/beast-mountain-bike.png', 'beast-full-suspension-mountain-bike', 'Beast | A mountainbike built for handling every terrain', 'Fly down the most technical off-road courses with ease with this full-suspension MTB.', 'The Beast is a high-performance full-suspension mountain bike built for riders who thrive on speed, technical terrain, and aggressive trail riding. Designed to charge through rock gardens, roots, berms, and rough descents, its advanced suspension system helps keep the wheels planted and in control when the trail gets demanding. Whether you''re attacking fast single-track, tackling challenging downhill sections, or pushing your limits on all-mountain adventures, the Beast delivers the confidence and capability needed to ride harder and faster.
Engineered for serious trail performance, the Beast combines responsive handling with exceptional traction to help riders maintain momentum through the roughest sections of trail. The full-suspension design absorbs impacts and reduces rider fatigue, allowing for greater control and comfort on long, demanding rides. From competitive events to weekend trail sessions, this premium trail mountain bike is built to maximize speed and precision where it matters most. For riders seeking a powerful and capable full-suspension MTB that excels on rugged single-track terrain, the Beast is ready to unleash its full potential.'),
('Egret', 'A lightweight aluminum frame, with handlebar basket, great for cruising around the city running errands.', 699.99, 10, '/images/egret-commuter-bike.png', 'egret-city-cruiser', 'Egret | A city bike with ease and comfort in mind', 'Cruise the city streets or take care of light shopping with the comfortable and easy-to-ride city bike.', 'The Egret is a lightweight and approachable city bike designed for riders who want an easy, comfortable way to get around town. Built around a lightweight aluminum frame, it offers smooth handling and effortless maneuverability, making it ideal for everyday errands, casual rides, and relaxed cruising through urban streets. With its integrated handlebar basket, the Egret makes it simple to carry essentials like groceries, a handbag, or work items without needing extra gear, making it a practical choice for new cyclists and city riders alike.
Beyond convenience, the Egret is designed to make daily travel enjoyable and stress-free. Its upright riding position promotes comfort and visibility in traffic, while its stable design helps new riders feel confident in busy environments. Whether you''re heading to the local market, meeting friends across town, or simply enjoying a leisurely ride, the Egret delivers a blend of practicality and charm that makes it a standout beginner-friendly commuter bike for everyday city life.'),
('Albatross', 'With a handlebar basket and rear rack, this is ideal for anyone wanting to commute by bike and pick up some groceries on the way home.', 999.99, 10, '/images/albatross-commuter-bike.png', 'albatross-rack-city-bike', 'Albatross | The perfect bike for commuting and shopping', 'With front and rear cargo space, you can commute in comfort and shop with ease.', 'The Albatross is a versatile commuter bike built for riders who want a reliable, practical, and comfortable way to travel through the city. Featuring a thoughtfully designed setup with a handlebar basket and rear rack, it makes carrying groceries, work supplies, or personal items effortless. Whether you''re commuting to the office, stopping by the store on the way home, or running errands across town, the Albatross is designed to handle daily life with ease and efficiency.
Engineered for comfort and utility, the Albatross provides a stable and upright riding position that keeps you relaxed and in control throughout your journey. Its balanced design makes stop-and-go city riding smooth and predictable, while its cargo-ready features add real-world practicality to every trip. For riders seeking a dependable and functional urban commuter bicycle, the Albatross offers the perfect combination of comfort, storage capacity, and everyday usability.'),
('Zappy', 'A 200-watt electric-assisted bicycle great for those who need just a little extra help getting up the hills.', 1499.99, 10, '/images/zappy-e-bike.png', 'zappy-e-bike', 'Zappy | Beginner e-bike', 'With 200w of power, this e-bike will let you have fun without draining your body''s battery.', 'The Zappy is a lightweight electric-assist bicycle designed to make cycling more accessible and enjoyable for riders of all experience levels. Equipped with a 200-watt electric motor, it provides just the right amount of assistance to help you tackle hills, headwinds, and longer rides without feeling overwhelmed. Whether you''re new to cycling, returning after a break, or simply looking for a little extra support, the Zappy makes every ride feel smoother and more achievable.
Perfect for daily commuting or relaxed recreational rides, the Zappy blends traditional cycling with modern electric assistance for a balanced and natural riding experience. The pedal-assist system engages seamlessly, helping you maintain momentum without taking away the feeling of riding a bike. For riders looking for an approachable entry-level e-bike, the Zappy delivers comfort, confidence, and just enough power to make challenging routes far more enjoyable.'),
('Bolt', 'A 500-watt electric bicycle great for those aging knees. Take on the hills and long rides again with confidence!', 2599.99, 10, '/images/bolt-e-bike.png', 'bolt-500-watt-e-bike', 'Bolt | Powerful e-bike for effortless riding', 'Effortly get around your neighborhood, the park, or the city with minimal effort thanks to the 500w pedal assist.', 'The Bolt is a powerful and dependable electric bicycle designed to bring confidence and freedom back to riders who want extra support on longer rides or challenging terrain. Featuring a robust 500-watt motor, it provides strong pedal assistance that makes climbing hills, covering distance, and riding against fatigue much easier. Whether you''re easing joint strain, returning to cycling after time away, or simply wanting a more effortless ride, the Bolt is built to help you go further with less effort.
Engineered for comfort and capability, the Bolt transforms demanding rides into smooth, enjoyable experiences. Its electric assist helps reduce stress on the knees and legs while maintaining a natural cycling feel, allowing riders to stay active without overexertion. From daily commuting to weekend adventures, this high-power e-bike delivers the strength, reliability, and comfort needed to rediscover the joy of riding with confidence.');